const BAND = {
  cold: { accent: T.blue,   bg: T.blueLight,   label: "Cold" },
  warm: { accent: T.orange, bg: T.orangeLight,  label: "Warm" },
  hot:  { accent: T.green,  bg: T.greenLight,   label: "Hot"  },
  sql:  { accent: T.purple, bg: T.purpleLight,  label: "SQL"  },
};

const scoreBand = (s, t) => s >= t.sql ? "sql" : s >= t.hot ? "hot" : s >= t.warm ? "warm" : "cold";
const bandOf    = (s, t) => BAND[scoreBand(s, t)];

