const Btn = ({ children, onClick, variant="primary", size="sm", icon:Icon, disabled, style:sx={} }) => {
  const [hov, setHov] = useState(false);
  const v = {
    primary:   { bg:hov?"#005f87":T.blue,   color:"#fff",   border:"none"                              },
    secondary: { bg:hov?T.blueLight:"#fff",  color:T.blue,  border:`1px solid ${hov?T.blue:T.border}`  },
    ghost:     { bg:hov?T.faint:"transparent",color:T.textSec,border:`1px solid ${T.border}`           },
    danger:    { bg:hov?"#b91c1c":T.red,     color:"#fff",   border:"none"                              },
    success:   { bg:hov?"#048a60":T.green,   color:"#fff",   border:"none"                              },
    outline:   { bg:"transparent",           color:T.textSec,border:`1px solid ${T.border}`             },
  }[variant]||{};
  const pad = {xs:"5px 10px",sm:"8px 15px",md:"10px 19px",lg:"12px 25px"}[size];
  const fs  = {xs:12,sm:13,md:14,lg:15}[size];
  return (
    <button onClick={onClick} disabled={disabled}
      onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
      style={{ display:"inline-flex",alignItems:"center",gap:7,background:v.bg,color:v.color,
        border:v.border||"none",borderRadius:8,padding:pad,fontSize:fs,fontWeight:700,
        fontFamily:T.body,cursor:disabled?"not-allowed":"pointer",opacity:disabled?.5:1,
        transition:"all .15s",whiteSpace:"nowrap",...sx }}>
      {Icon && <Icon size={fs} />}
      {children}
    </button>
  );
};

