/* ═══════════════════════════════════════════════════════════
   TAB 1 — SCORING DASHBOARD
═══════════════════════════════════════════════════════════ */
const ScoringDashboard = ({ leads, thresholds, history }) => {
  const bands = useMemo(() => {
    const c={cold:0,warm:0,hot:0,sql:0};
    leads.forEach(l=>c[scoreBand(l.score,thresholds)]++);
    return c;
  },[leads,thresholds]);

  const topLeads = useMemo(()=>[...leads].sort((a,b)=>b.score-a.score).slice(0,10),[leads]);
  const movements = useMemo(()=>leads.map(l=>({...l,delta:l.score-l.prevScore})).filter(l=>l.delta!==0).sort((a,b)=>Math.abs(b.delta)-Math.abs(a.delta)),[leads]);

  const donutSlices = [
    {label:"Cold",value:bands.cold,color:T.blue},
    {label:"Warm",value:bands.warm,color:T.orange},
    {label:"Hot", value:bands.hot, color:T.green},
    {label:"SQL", value:bands.sql, color:T.purple},
  ].filter(s=>s.value>0);

  const totalLeads = leads.length;
  const avgScore = Math.round(leads.reduce((a,l)=>a+l.score,0)/totalLeads);

  return (
    <div style={{ display:"flex",flexDirection:"column",gap:20 }}>
      {/* Alert banners */}
      <div style={{ display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12 }}>
        {[
          { Icon:Star,        color:T.purple, bg:T.purpleLight, msg:`${bands.sql} leads atingiram threshold SQL` },
          { Icon:TrendingUp,  color:T.green,  bg:T.greenLight,  msg:`${bands.hot} leads na faixa Hot — prontos para abordagem` },
          { Icon:AlertTriangle,color:T.orange,bg:T.orangeLight, msg:`${movements.filter(m=>m.delta<0).length} leads perderam pontos esta semana` },
        ].map((a,i)=>(
          <div key={i} style={{ background:a.bg,border:`1px solid ${a.color}30`,
            borderRadius:11,padding:"12px 16px",display:"flex",alignItems:"center",gap:10 }}>
            <a.Icon size={18} color={a.color}/>
            <span style={{ fontFamily:T.body,fontSize:13,fontWeight:600,color:a.color }}>{a.msg}</span>
          </div>
        ))}
      </div>

      {/* KPI row */}
      <div style={{ display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:14 }}>
        {[
          { Icon:Users,    label:"Total de leads",  value:totalLeads,  color:T.blue   },
          { Icon:Activity, label:"Score médio",      value:avgScore,    color:T.teal   },
          { Icon:Star,     label:"Leads SQL",         value:bands.sql,   color:T.purple },
          { Icon:Zap,      label:"Mudanças hoje",
            value:history.filter(h=>new Date(h.timestamp)>new Date(Date.now()-864e5)).length,
            color:T.orange },
        ].map(s=>(
          <Card key={s.label} style={{ padding:"18px 20px" }}>
            <div style={{ width:39,height:39,borderRadius:10,background:`${s.color}14`,
              display:"flex",alignItems:"center",justifyContent:"center",marginBottom:14 }}>
              <s.Icon size={19} color={s.color}/>
            </div>
            <div style={{ fontSize:29,fontWeight:700,color:T.text,fontFamily:T.heading,
              letterSpacing:"-0.03em",lineHeight:1 }}>{s.value}</div>
            <div style={{ fontSize:13,color:T.textSec,fontFamily:T.body,marginTop:4 }}>{s.label}</div>
          </Card>
        ))}
      </div>

      {/* Main grid */}
      <div style={{ display:"grid",gridTemplateColumns:"220px 1fr 260px",gap:16 }}>
        {/* Donut */}
        <Card style={{ display:"flex",flexDirection:"column",alignItems:"center",padding:"20px 16px" }}>
          <SectionTitle>Distribuição por faixa</SectionTitle>
          <DonutChart slices={donutSlices} size={140}/>
          <div style={{ width:"100%",marginTop:16,display:"flex",flexDirection:"column",gap:7 }}>
            {donutSlices.map(s=>(
              <div key={s.label} style={{ display:"flex",justifyContent:"space-between",alignItems:"center" }}>
                <div style={{ display:"flex",alignItems:"center",gap:7 }}>
                  <div style={{ width:9,height:9,borderRadius:"50%",background:s.color }}/>
                  <span style={{ fontFamily:T.body,fontSize:13,fontWeight:600,color:T.text }}>{s.label}</span>
                </div>
                <div style={{ display:"flex",alignItems:"center",gap:6 }}>
                  <span style={{ fontFamily:T.heading,fontSize:14,fontWeight:700,color:s.color }}>{s.value}</span>
                  <span style={{ fontFamily:T.body,fontSize:11,color:T.textTer }}>{Math.round(s.value/totalLeads*100)}%</span>
                </div>
              </div>
            ))}
          </div>
        </Card>

        {/* Top 10 */}
        <Card>
          <SectionTitle sub="Rankeados por score atual">Top 10 leads esta semana</SectionTitle>
          <div>
            {topLeads.map((l,i)=>{
              const band = bandOf(l.score,thresholds);
              const spark = Array.from({length:7},(_,j)=>Math.max(0,l.score-(6-j)*3+Math.floor(Math.random()*6-3)));
              return (
                <div key={l.id} style={{ display:"flex",alignItems:"center",gap:10,
                  padding:"8px 0",borderBottom:`1px solid ${T.border}` }}>
                  <span style={{ fontFamily:T.body,fontSize:12,fontWeight:700,color:T.textTer,
                    width:20,textAlign:"right",flexShrink:0 }}>#{i+1}</span>
                  <div style={{ width:30,height:30,borderRadius:"50%",background:band.bg,
                    border:`1.5px solid ${band.accent}`,display:"flex",alignItems:"center",
                    justifyContent:"center",flexShrink:0 }}>
                    <span style={{ fontFamily:T.body,fontSize:10,fontWeight:700,color:band.accent }}>
                      {l.name.split(" ").map(w=>w[0]).join("").slice(0,2)}
                    </span>
                  </div>
                  <div style={{ flex:1,minWidth:0 }}>
                    <div style={{ fontFamily:T.body,fontSize:13,fontWeight:700,color:T.text,
                      whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis" }}>{l.name}</div>
                    <div style={{ fontFamily:T.body,fontSize:11,color:T.textSec }}>{l.company}</div>
                  </div>
                  <Spark data={spark} color={band.accent}/>
                  <span style={{ fontFamily:T.heading,fontSize:17,fontWeight:700,color:band.accent,
                    width:36,textAlign:"right" }}>{l.score}</span>
                  <BandPill band={band}/>
                </div>
              );
            })}
          </div>
        </Card>

        {/* Movements */}
        <Card accent>
          <SectionTitle>Maiores mudanças</SectionTitle>
          {movements.slice(0,9).map(l=>{
            const up=l.delta>0;
            return (
              <div key={l.id} style={{ display:"flex",alignItems:"center",gap:8,
                padding:"7px 0",borderBottom:`1px solid ${T.border}` }}>
                {up?<TrendingUp size={14} color={T.green}/>:<TrendingDown size={14} color={T.red}/>}
                <div style={{ flex:1,minWidth:0 }}>
                  <div style={{ fontFamily:T.body,fontSize:13,fontWeight:700,color:T.text,
                    whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis" }}>
                    {l.name.split(" ")[0]}
                  </div>
                  <div style={{ display:"flex",gap:4,alignItems:"center" }}>
                    <span style={{ fontFamily:T.body,fontSize:11,color:T.textTer }}>{l.prevScore}</span>
                    <span style={{ fontSize:10,color:T.textTer }}>→</span>
                    <span style={{ fontFamily:T.body,fontSize:11,color:up?T.green:T.red,fontWeight:700 }}>{l.score}</span>
                  </div>
                </div>
                <span style={{ fontFamily:T.heading,fontSize:14,fontWeight:700,
                  color:up?T.green:T.red }}>
                  {up?"+":""}{l.delta}
                </span>
              </div>
            );
          })}
        </Card>
      </div>
    </div>
  );
};

/* ═══════════════════════════════════════════════════════════
   TAB 2 — SCORING RULES
═══════════════════════════════════════════════════════════ */
const ScoringRules = ({ rules, setRules, thresholds, setThresholds, leads }) => {
  const [editId,setEditId] = useState(null);
  const [showAdd,setShowAdd] = useState(false);
  const [newRule,setNewRule] = useState({label:"",points:5,category:"email"});
  const positiveRules = rules.filter(r=>r.points>0);
  const decayRules    = rules.filter(r=>r.points<0);

  const update = (id,key,val) => setRules(p=>p.map(r=>r.id===id?{...r,[key]:val}:r));
  const del    = (id) => setRules(p=>p.filter(r=>r.id!==id));
  const add    = () => {
    if(!newRule.label) return;
    setRules(p=>[...p,{...newRule,id:`r${Date.now()}`,action:newRule.label.toLowerCase().replace(/\s/g,"_"),active:true,points:Number(newRule.points)}]);
    setNewRule({label:"",points:5,category:"email"});
    setShowAdd(false);
  };

  const RuleRow = ({rule}) => {
    const [hov,setHov]=useState(false);
    const isEdit=editId===rule.id;
    const isPositive=rule.points>=0;
    return (
      <div onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
        style={{ display:"flex",alignItems:"center",gap:12,padding:"10px 14px",
          background:hov?T.faint:"transparent",borderRadius:8,
          borderBottom:`1px solid ${T.border}`,transition:"background .15s" }}>
        <div style={{ width:9,height:9,borderRadius:"50%",flexShrink:0,
          background:rule.active?(isPositive?T.green:T.red):T.textTer }}/>
        {isEdit?(
          <>
            <input value={rule.label} onChange={e=>update(rule.id,"label",e.target.value)}
              style={{ flex:1,fontFamily:T.body,fontSize:13,padding:"5px 10px",
                border:`1.5px solid ${T.blue}`,borderRadius:7,color:T.text,outline:"none" }}/>
            <input value={rule.points} onChange={e=>update(rule.id,"points",Number(e.target.value))}
              type="number"
              style={{ width:70,fontFamily:T.body,fontSize:13,padding:"5px 10px",
                border:`1.5px solid ${T.blue}`,borderRadius:7,color:T.text,
                outline:"none",textAlign:"center" }}/>
            <Btn onClick={()=>setEditId(null)} variant="success" size="xs" icon={Check}>OK</Btn>
          </>
        ):(
          <>
            <span style={{ flex:1,fontFamily:T.body,fontSize:13,fontWeight:600,color:T.text }}>{rule.label}</span>
            <span style={{ fontFamily:T.heading,fontSize:14,fontWeight:700,
              color:isPositive?T.green:T.red,width:46,textAlign:"right" }}>
              {isPositive?"+":""}{rule.points}
            </span>
            <span style={{ fontFamily:T.body,fontSize:11,fontWeight:600,color:T.textSec,
              background:T.faint,border:`1px solid ${T.border}`,
              padding:"2px 8px",borderRadius:6 }}>{rule.category}</span>
            <Toggle checked={rule.active} onChange={v=>update(rule.id,"active",v)}/>
            {hov&&(
              <div style={{ display:"flex",gap:4 }}>
                <Btn onClick={()=>setEditId(rule.id)} variant="ghost" size="xs" icon={Edit2}/>
                <Btn onClick={()=>del(rule.id)} variant="danger" size="xs" icon={Trash2}/>
              </div>
            )}
          </>
        )}
      </div>
    );
  };

  return (
    <div style={{ display:"grid",gridTemplateColumns:"1fr 340px",gap:20 }}>
      <div style={{ display:"flex",flexDirection:"column",gap:16 }}>
        {/* Positive rules */}
        <Card>
          <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14 }}>
            <SectionTitle>Regras de pontuação positiva</SectionTitle>
            <Btn onClick={()=>setShowAdd(!showAdd)} variant="secondary" size="sm" icon={Plus}>Nova regra</Btn>
          </div>
          {showAdd&&(
            <div style={{ display:"flex",gap:8,padding:"12px 14px",background:T.blueLight,
              borderRadius:9,marginBottom:12,alignItems:"center" }}>
              <input placeholder="Nome da regra..." value={newRule.label}
                onChange={e=>setNewRule(p=>({...p,label:e.target.value}))}
                style={{ flex:1,fontFamily:T.body,fontSize:13,padding:"7px 11px",
                  border:`1px solid ${T.border}`,borderRadius:7,color:T.text,outline:"none" }}/>
              <input type="number" value={newRule.points} placeholder="Pts"
                onChange={e=>setNewRule(p=>({...p,points:Number(e.target.value)}))}
                style={{ width:70,fontFamily:T.body,fontSize:13,padding:"7px 11px",
                  border:`1px solid ${T.border}`,borderRadius:7,color:T.text,
                  outline:"none",textAlign:"center" }}/>
              <select value={newRule.category} onChange={e=>setNewRule(p=>({...p,category:e.target.value}))}
                style={{ fontFamily:T.body,fontSize:12,padding:"7px 10px",
                  border:`1px solid ${T.border}`,borderRadius:7,color:T.text,background:"#fff" }}>
                {["email","form","página","whatsapp","evento"].map(c=><option key={c}>{c}</option>)}
              </select>
              <Btn onClick={add} variant="success" size="sm" icon={Check}>Adicionar</Btn>
              <Btn onClick={()=>setShowAdd(false)} variant="ghost" size="sm" icon={X}/>
            </div>
          )}
          <div style={{ padding:"4px 0" }}>
            {positiveRules.map(r=><RuleRow key={r.id} rule={r}/>)}
          </div>
        </Card>

        {/* Decay rules */}
        <Card accentColor={T.red} accent>
          <SectionTitle sub="Penalizações automáticas por comportamento negativo">
            Regras de decaimento
          </SectionTitle>
          <div style={{ padding:"4px 0" }}>
            {decayRules.map(r=><RuleRow key={r.id} rule={r}/>)}
          </div>
        </Card>
      </div>

      {/* Right column */}
      <div style={{ display:"flex",flexDirection:"column",gap:16 }}>
        {/* Thresholds */}
        <Card accent>
          <SectionTitle sub="Defina os limites de score para cada faixa">Thresholds de faixa</SectionTitle>
          {[
            {key:"warm",label:"Cold → Warm",color:T.orange },
            {key:"hot", label:"Warm → Hot", color:T.green  },
            {key:"sql", label:"Hot → SQL",  color:T.purple },
          ].map(t=>(
            <div key={t.key} style={{ marginBottom:18 }}>
              <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:7 }}>
                <span style={{ fontFamily:T.body,fontSize:13,fontWeight:700,color:t.color }}>{t.label}</span>
                <span style={{ fontFamily:T.heading,fontSize:15,fontWeight:700,color:t.color }}>
                  {thresholds[t.key]} pts
                </span>
              </div>
              <input type="range" min="0" max="100" value={thresholds[t.key]}
                onChange={e=>setThresholds(p=>({...p,[t.key]:Number(e.target.value)}))}
                style={{ width:"100%",accentColor:t.color,marginBottom:5 }}/>
              <ScoreBar value={thresholds[t.key]} color={t.color}/>
            </div>
          ))}
          {/* Band strip */}
          <div style={{ marginTop:8,height:26,borderRadius:8,overflow:"hidden",display:"flex" }}>
            {[
              {label:"Cold", color:T.blue,   pct:thresholds.warm},
              {label:"Warm", color:T.orange, pct:thresholds.hot-thresholds.warm},
              {label:"Hot",  color:T.green,  pct:thresholds.sql-thresholds.hot},
              {label:"SQL",  color:T.purple, pct:100-thresholds.sql},
            ].filter(b=>b.pct>0).map(b=>(
              <div key={b.label} style={{ flex:`0 0 ${b.pct}%`,background:`${b.color}20`,
                display:"flex",alignItems:"center",justifyContent:"center",
                borderRight:`1px solid ${T.bg}` }}>
                <span style={{ fontFamily:T.body,fontSize:10,fontWeight:700,color:b.color,
                  letterSpacing:"0.06em" }}>{b.label}</span>
              </div>
            ))}
          </div>
        </Card>

        {/* Live preview */}
        <Card>
          <SectionTitle>Preview de leads</SectionTitle>
          {leads.slice(0,6).map(l=>{
            const band=bandOf(l.score,thresholds);
            return (
              <div key={l.id} style={{ display:"flex",alignItems:"center",gap:9,
                padding:"7px 0",borderBottom:`1px solid ${T.border}` }}>
                <div style={{ width:9,height:9,borderRadius:"50%",background:band.accent,flexShrink:0 }}/>
                <span style={{ fontFamily:T.body,fontSize:13,fontWeight:600,color:T.text,flex:1 }}>
                  {l.name.split(" ")[0]}
                </span>
                <ScoreBar value={l.score} color={band.accent}/>
                <span style={{ fontFamily:T.heading,fontSize:14,fontWeight:700,color:band.accent,width:30,textAlign:"right" }}>{l.score}</span>
                <BandPill band={band}/>
              </div>
            );
          })}
        </Card>
      </div>
    </div>
  );
};

/* ═══════════════════════════════════════════════════════════
   TAB 3 — SEGMENT BUILDER
═══════════════════════════════════════════════════════════ */
const SegmentBuilder = ({ leads, thresholds }) => {
  const [segments,setSegments] = useState(DEFAULT_SEGMENTS);
  const [active,setActive]     = useState(null);
  const [draft,setDraft]       = useState({name:"",conditions:[],logic:"AND",color:T.blue});
  const [saved,setSaved]       = useState(false);

  const evaluate = (lead,conditions,logic) => {
    const r = conditions.map(c=>{
      switch(c.op){
        case"gte": return Number(lead[c.field])>=Number(c.value);
        case"lte": return Number(lead[c.field])<=Number(c.value);
        case"eq":  return String(lead[c.field]).toLowerCase()===c.value.toLowerCase();
        case"neq": return String(lead[c.field]).toLowerCase()!==c.value.toLowerCase();
        case"contains": return c.field==="tags"?(lead.tags||[]).some(t=>t.toLowerCase().includes(c.value.toLowerCase())):String(lead[c.field]).toLowerCase().includes(c.value.toLowerCase());
        case"not_contains": return c.field==="tags"?!(lead.tags||[]).some(t=>t.toLowerCase().includes(c.value.toLowerCase())):!String(lead[c.field]).toLowerCase().includes(c.value.toLowerCase());
        case"days_ago": return (Date.now()-new Date(lead.lastActive).getTime())>Number(c.value)*864e5;
        case"days_within": return (Date.now()-new Date(lead.lastActive).getTime())<Number(c.value)*864e5;
        default: return false;
      }
    });
    return logic==="AND"?r.every(Boolean):r.some(Boolean);
  };

  const matchCount = useMemo(()=>draft.conditions.length?leads.filter(l=>evaluate(l,draft.conditions,draft.logic)).length:0,[draft,leads]);
  const matchLeads = useMemo(()=>draft.conditions.length?leads.filter(l=>evaluate(l,draft.conditions,draft.logic)).slice(0,6):[],[draft,leads]);

  const addCond = () => setDraft(d=>({...d,conditions:[...d.conditions,{id:`c${Date.now()}`,field:"score",op:"gte",value:"60"}]}));
  const updCond = (id,k,v) => setDraft(d=>({...d,conditions:d.conditions.map(c=>c.id===id?{...c,[k]:v}:c)}));
  const delCond = (id) => setDraft(d=>({...d,conditions:d.conditions.filter(c=>c.id!==id)}));

  const saveSeg = () => {
    if(!draft.name||!draft.conditions.length) return;
    const seg={...draft,id:active||`seg${Date.now()}`,count:matchCount,saved:true};
    setSegments(p=>active?p.map(s=>s.id===active?seg:s):[...p,seg]);
    setDraft({name:"",conditions:[],logic:"AND",color:T.blue});
    setActive(null); setSaved(true); setTimeout(()=>setSaved(false),2500);
  };

  const liveCounts = useMemo(()=>segments.map(s=>({...s,liveCount:leads.filter(l=>evaluate(l,s.conditions,s.logic)).length})),[segments,leads]);
  const COLORS = [T.blue,T.teal,T.green,T.orange,T.red,T.purple];

  return (
    <div style={{ display:"grid",gridTemplateColumns:"280px 1fr",gap:20 }}>
      {/* Saved segments */}
      <div>
        <div style={{ fontFamily:T.body,fontSize:12,fontWeight:700,color:T.textSec,
          textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:10 }}>Segmentos salvos</div>
        <div style={{ display:"flex",flexDirection:"column",gap:8,marginBottom:12 }}>
          {liveCounts.map(seg=>(
            <div key={seg.id} onClick={()=>{ setDraft({name:seg.name,conditions:[...seg.conditions],logic:seg.logic,color:seg.color}); setActive(seg.id); }}
              style={{ background:active===seg.id?T.blueLight:T.surface,
                border:`1px solid ${active===seg.id?T.blue:T.border}`,
                borderLeft:`3px solid ${seg.color}`,
                borderRadius:10,padding:"12px 14px",cursor:"pointer",transition:"all .15s" }}>
              <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center" }}>
                <span style={{ fontFamily:T.body,fontSize:13,fontWeight:700,color:T.text }}>{seg.name}</span>
                <span style={{ fontFamily:T.heading,fontSize:14,fontWeight:700,color:seg.color }}>{seg.liveCount}</span>
              </div>
              <div style={{ fontFamily:T.body,fontSize:11,color:T.textSec,marginTop:4,display:"flex",gap:4,flexWrap:"wrap" }}>
                {seg.conditions.slice(0,2).map((c,i)=>(
                  <span key={i} style={{ background:T.faint,border:`1px solid ${T.border}`,
                    padding:"1px 7px",borderRadius:5 }}>{c.field} {OP_LABELS[c.op]} {c.value}</span>
                ))}
                {seg.conditions.length>2&&<span style={{ color:T.textTer }}>+{seg.conditions.length-2}</span>}
              </div>
            </div>
          ))}
        </div>
        <Btn onClick={()=>{setDraft({name:"",conditions:[],logic:"AND",color:T.blue});setActive(null);}}
          variant="ghost" size="sm" icon={Plus} sx={{ width:"100%",justifyContent:"center" }}>
          Novo segmento
        </Btn>
      </div>

      {/* Builder */}
      <div>
        <div style={{ display:"flex",gap:12,alignItems:"center",marginBottom:16,flexWrap:"wrap" }}>
          <input placeholder="Nome do segmento..." value={draft.name}
            onChange={e=>setDraft(d=>({...d,name:e.target.value}))}
            style={{ flex:1,fontFamily:T.body,fontSize:13,fontWeight:600,padding:"8px 13px",
              border:`1px solid ${T.border}`,borderRadius:8,color:T.text,outline:"none" }}/>
          <div style={{ display:"flex",gap:5,alignItems:"center" }}>
            <span style={{ fontFamily:T.body,fontSize:12,fontWeight:600,color:T.textSec }}>Lógica:</span>
            {["AND","OR","NOT"].map(l=>(
              <button key={l} onClick={()=>setDraft(d=>({...d,logic:l}))}
                style={{ padding:"6px 11px",fontFamily:T.body,fontSize:12,fontWeight:700,
                  borderRadius:6,border:`1.5px solid ${draft.logic===l?T.blue:T.border}`,
                  background:draft.logic===l?T.blueLight:"transparent",
                  color:draft.logic===l?T.blue:T.textSec,cursor:"pointer" }}>
                {l}
              </button>
            ))}
          </div>
          <div style={{ display:"flex",gap:5 }}>
            {COLORS.map(col=>(
              <div key={col} onClick={()=>setDraft(d=>({...d,color:col}))}
                style={{ width:19,height:19,borderRadius:"50%",background:col,cursor:"pointer",
                  border:`2.5px solid ${draft.color===col?"#fff":"transparent"}`,
                  outline:draft.color===col?`2px solid ${col}`:undefined }}/>
            ))}
          </div>
        </div>

        {/* Conditions */}
        <Card style={{ marginBottom:14 }}>
          {draft.conditions.length===0&&(
            <div style={{ textAlign:"center",padding:"24px 0",color:T.textSec,
              fontFamily:T.body,fontSize:13,fontWeight:600 }}>
              Adicione condições para filtrar leads.
            </div>
          )}
          {draft.conditions.map((cond,i)=>{
            const fm=CONDITION_FIELDS.find(f=>f.value===cond.field);
            return (
              <div key={cond.id} style={{ display:"flex",gap:8,alignItems:"center",
                padding:"9px 0",borderBottom:i<draft.conditions.length-1?`1px solid ${T.border}`:"none" }}>
                {i>0&&(
                  <div style={{ fontFamily:T.body,fontSize:11,fontWeight:700,color:T.blue,
                    background:T.blueLight,padding:"3px 8px",borderRadius:5,minWidth:38,textAlign:"center" }}>
                    {draft.logic}
                  </div>
                )}
                {i===0&&<div style={{ width:46 }}/>}
                <select value={cond.field} onChange={e=>updCond(cond.id,"field",e.target.value)}
                  style={{ fontFamily:T.body,fontSize:13,background:T.faint,
                    border:`1px solid ${T.border}`,borderRadius:7,padding:"7px 10px",
                    color:T.text,outline:"none" }}>
                  {CONDITION_FIELDS.map(f=><option key={f.value} value={f.value}>{f.label}</option>)}
                </select>
                <select value={cond.op} onChange={e=>updCond(cond.id,"op",e.target.value)}
                  style={{ fontFamily:T.body,fontSize:13,background:T.faint,
                    border:`1px solid ${T.border}`,borderRadius:7,padding:"7px 10px",
                    color:T.teal,outline:"none" }}>
                  {(fm?.ops||["eq"]).map(op=><option key={op} value={op}>{OP_LABELS[op]}</option>)}
                </select>
                <input value={cond.value} onChange={e=>updCond(cond.id,"value",e.target.value)}
                  placeholder="Valor..."
                  style={{ flex:1,fontFamily:T.body,fontSize:13,padding:"7px 11px",
                    border:`1px solid ${T.border}`,borderRadius:7,color:T.text,outline:"none" }}/>
                <button onClick={()=>delCond(cond.id)}
                  style={{ background:"none",border:"none",cursor:"pointer",color:T.red,
                    display:"flex",padding:4 }}>
                  <X size={15}/>
                </button>
              </div>
            );
          })}
          <div style={{ marginTop:10 }}>
            <Btn onClick={addCond} variant="ghost" size="xs" icon={Plus}>Adicionar condição</Btn>
          </div>
        </Card>

        {/* Live preview */}
        {draft.conditions.length>0&&(
          <div style={{ background:draft.color+"10",border:`1px solid ${draft.color}30`,
            borderRadius:12,padding:"14px 16px",marginBottom:14 }}>
            <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10 }}>
              <span style={{ fontFamily:T.body,fontSize:13,fontWeight:600,color:T.textSec }}>Preview em tempo real</span>
              <div style={{ display:"flex",alignItems:"center",gap:8 }}>
                <span style={{ fontFamily:T.heading,fontSize:23,fontWeight:700,color:draft.color }}>{matchCount}</span>
                <span style={{ fontFamily:T.body,fontSize:13,fontWeight:600,color:T.textSec }}>leads correspondem</span>
              </div>
            </div>
            <div style={{ display:"flex",flexWrap:"wrap",gap:6 }}>
              {matchLeads.map(l=>{
                const band=bandOf(l.score,{warm:21,hot:51,sql:80});
                return (
                  <div key={l.id} style={{ display:"flex",alignItems:"center",gap:6,
                    background:T.surface,border:`1px solid ${T.border}`,
                    borderRadius:7,padding:"5px 11px" }}>
                    <div style={{ width:7,height:7,borderRadius:"50%",background:band.accent }}/>
                    <span style={{ fontFamily:T.body,fontSize:12,fontWeight:600,color:T.text }}>{l.name.split(" ")[0]}</span>
                    <span style={{ fontFamily:T.heading,fontSize:12,fontWeight:700,color:band.accent }}>{l.score}</span>
                  </div>
                );
              })}
              {matchCount>6&&<div style={{ fontFamily:T.body,fontSize:12,fontWeight:600,color:T.textSec,padding:"5px 8px" }}>+{matchCount-6} mais</div>}
            </div>
          </div>
        )}

        <div style={{ display:"flex",gap:8,justifyContent:"flex-end" }}>
          {active&&<Btn onClick={()=>{setSegments(p=>p.filter(s=>s.id!==active));setActive(null);setDraft({name:"",conditions:[],logic:"AND",color:T.blue});}} variant="danger" size="sm" icon={Trash2}>Excluir</Btn>}
          <Btn onClick={saveSeg} variant="success" size="sm" icon={saved?Check:Save}
            disabled={!draft.name||!draft.conditions.length}>
            {saved?"Salvo!":active?"Atualizar segmento":"Salvar segmento"}
          </Btn>
        </div>
      </div>
    </div>
  );
};

/* ═══════════════════════════════════════════════════════════
   TAB 4 — AUTOMAÇÃO & LOG
═══════════════════════════════════════════════════════════ */
const ACTION_LABELS = {
  send_webhook:"Webhook",notify_slack:"Slack",assign_sdR:"Atribuir SDR",
  start_sequence:"Sequência",start_reactivation:"Reativação",flag_review:"Revisar",
};

const AutomationLog = ({ leads, history, thresholds }) => {
  const [webhookUrl,setWebhookUrl] = useState("https://hooks.zapier.com/hooks/catch/xxxxx/");
  const [webhookActive,setWebhookActive] = useState(true);
  const [triggers,setTriggers] = useState([
    {id:"t1",label:"Lead entra na faixa SQL",  actions:["send_webhook","notify_slack","assign_sdR"],active:true, color:T.purple},
    {id:"t2",label:"Lead entra na faixa Hot",  actions:["send_webhook","start_sequence"],           active:true, color:T.green },
    {id:"t3",label:"Score cai mais de 20 pts", actions:["send_webhook","flag_review"],              active:false,color:T.red   },
    {id:"t4",label:"Inativo por 30+ dias",     actions:["start_reactivation","send_webhook"],       active:true, color:T.orange},
  ]);
  const [filter,setFilter] = useState("all");
  const [logPage,setLogPage] = useState(1);
  const LOG_PAGE=12;

  const filteredLog = useMemo(()=>{
    if(filter==="up")      return history.filter(h=>h.new_score>h.old_score);
    if(filter==="down")    return history.filter(h=>h.new_score<h.old_score);
    if(filter==="webhook") return history.filter(h=>h.webhook_sent);
    return history;
  },[history,filter]);

  const pageLog=filteredLog.slice((logPage-1)*LOG_PAGE,logPage*LOG_PAGE);
  const totalPages=Math.ceil(filteredLog.length/LOG_PAGE);

  return (
    <div style={{ display:"flex",flexDirection:"column",gap:18 }}>
      <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:18 }}>
        {/* Triggers */}
        <Card>
          <SectionTitle sub="Ações executadas quando leads mudam de faixa">Triggers automáticos</SectionTitle>
          <div style={{ display:"flex",flexDirection:"column",gap:10 }}>
            {triggers.map(t=>(
              <div key={t.id} style={{ padding:"13px 14px",
                background:t.active?`${t.color}08`:T.faint,
                border:`1px solid ${t.active?t.color+"30":T.border}`,
                borderLeft:`3px solid ${t.active?t.color:T.border}`,
                borderRadius:9 }}>
                <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8 }}>
                  <span style={{ fontFamily:T.body,fontSize:13,fontWeight:700,
                    color:t.active?T.text:T.textSec }}>{t.label}</span>
                  <Toggle checked={t.active} onChange={v=>setTriggers(p=>p.map(x=>x.id===t.id?{...x,active:v}:x))}/>
                </div>
                <div style={{ display:"flex",gap:5,flexWrap:"wrap" }}>
                  {t.actions.map(a=>(
                    <span key={a} style={{ fontFamily:T.body,fontSize:11,fontWeight:600,
                      background:t.active?`${t.color}14`:T.faint,
                      color:t.active?t.color:T.textSec,
                      padding:"3px 9px",borderRadius:6 }}>
                      {ACTION_LABELS[a]||a}
                    </span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </Card>

        {/* Webhook */}
        <Card accent>
          <SectionTitle sub="Endpoint para notificações de scoring">Webhook config</SectionTitle>
          <div style={{ marginBottom:14 }}>
            <div style={{ fontFamily:T.body,fontSize:12,fontWeight:700,color:T.textSec,
              textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:7 }}>URL do Endpoint</div>
            <input value={webhookUrl} onChange={e=>setWebhookUrl(e.target.value)}
              style={{ width:"100%",fontFamily:"monospace",fontSize:12,padding:"8px 12px",
                border:`1px solid ${T.border}`,borderRadius:8,color:T.text,
                background:T.faint,outline:"none" }}/>
          </div>
          <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",
            marginBottom:16,padding:"10px 14px",background:T.faint,
            border:`1px solid ${T.border}`,borderRadius:8 }}>
            <span style={{ fontFamily:T.body,fontSize:13,fontWeight:700,color:T.text }}>Webhook ativo</span>
            <Toggle checked={webhookActive} onChange={setWebhookActive}/>
          </div>
          <div style={{ fontFamily:T.body,fontSize:12,fontWeight:600,color:T.textSec,marginBottom:8 }}>
            Payload de exemplo:
          </div>
          <pre style={{ fontFamily:"monospace",fontSize:11,color:"#7dd3fc",background:"#0f172a",
            borderRadius:9,padding:"12px 14px",margin:0,overflow:"auto",lineHeight:1.7 }}>{`{
  "event": "band_change",
  "lead_id": "l14",
  "lead_name": "Carlos Mendes",
  "old_score": 48,
  "new_score": 61,
  "old_band": "warm",
  "new_band": "hot"
}`}</pre>
          <div style={{ marginTop:12,display:"flex",gap:8 }}>
            <Btn variant="secondary" size="sm" icon={Send}>Testar webhook</Btn>
            <Btn variant="ghost" size="sm" icon={RefreshCw}>Ver envios</Btn>
          </div>
        </Card>
      </div>

      {/* Score change log */}
      <Card style={{ padding:0,overflow:"hidden" }}>
        <div style={{ padding:"15px 20px",borderBottom:`1px solid ${T.border}`,
          display:"flex",justifyContent:"space-between",alignItems:"center" }}>
          <div>
            <h2 style={{ fontSize:15,fontWeight:700,color:T.text,fontFamily:T.heading,margin:0 }}>Log de mudanças de score</h2>
            <p style={{ fontSize:12,fontWeight:600,color:T.textSec,margin:"3px 0 0",fontFamily:T.body }}>{history.length} eventos registrados</p>
          </div>
          <div style={{ display:"flex",gap:6 }}>
            {[["all","Todos"],["up","↑ Subida"],["down","↓ Queda"],["webhook","Webhook"]].map(([val,label])=>(
              <button key={val} onClick={()=>{setFilter(val);setLogPage(1);}}
                style={{ padding:"6px 12px",fontFamily:T.body,fontSize:12,fontWeight:filter===val?700:500,
                  borderRadius:7,border:`1.5px solid ${filter===val?T.blue:T.border}`,
                  background:filter===val?T.blueLight:"transparent",
                  color:filter===val?T.blue:T.textSec,cursor:"pointer" }}>
                {label}
              </button>
            ))}
          </div>
        </div>
        <div style={{ overflowX:"auto" }}>
          <table style={{ width:"100%",borderCollapse:"collapse",minWidth:680 }}>
            <thead>
              <tr style={{ background:T.faint,borderBottom:`1.5px solid ${T.border}` }}>
                {["Timestamp","Lead","Score ant.","Novo score","Δ","Motivo","Webhook"].map(h=>(
                  <th key={h} style={{ padding:"9px 14px",textAlign:"left",fontFamily:T.body,
                    fontSize:11,fontWeight:700,color:T.textSec,textTransform:"uppercase",
                    letterSpacing:"0.05em",whiteSpace:"nowrap" }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {pageLog.map(h=>{
                const delta=h.new_score-h.old_score, up=delta>0;
                return (
                  <tr key={h.id} style={{ borderBottom:`1px solid ${T.faint}` }}
                    onMouseEnter={e=>e.currentTarget.style.background=T.faint}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                    <td style={{ padding:"10px 14px",fontFamily:"monospace",fontSize:12,fontWeight:600,color:T.textSec,whiteSpace:"nowrap" }}>
                      {new Date(h.timestamp).toLocaleString("pt-BR",{day:"2-digit",month:"short",hour:"2-digit",minute:"2-digit"})}
                    </td>
                    <td style={{ padding:"10px 14px",fontFamily:T.body,fontSize:13,fontWeight:700,color:T.text }}>{h.lead_name}</td>
                    <td style={{ padding:"10px 14px",fontFamily:T.heading,fontSize:13,fontWeight:700,color:T.textSec }}>{h.old_score}</td>
                    <td style={{ padding:"10px 14px",fontFamily:T.heading,fontSize:14,fontWeight:700,
                      color:bandOf(h.new_score,{warm:21,hot:51,sql:80}).accent }}>{h.new_score}</td>
                    <td style={{ padding:"10px 14px",fontFamily:T.heading,fontSize:13,fontWeight:700,
                      color:up?T.green:T.red }}>{up?"+":""}{delta}</td>
                    <td style={{ padding:"10px 14px",fontFamily:T.body,fontSize:12,fontWeight:600,color:T.textSec }}>{h.reason}</td>
                    <td style={{ padding:"10px 14px" }}>
                      {h.webhook_sent?(
                        <span style={{ fontFamily:T.body,fontSize:11,fontWeight:700,color:T.green,
                          background:T.greenLight,padding:"3px 9px",borderRadius:6,display:"flex",
                          alignItems:"center",gap:4,width:"fit-content" }}>
                          <Check size={11}/> enviado
                        </span>
                      ):(
                        <span style={{ color:T.textTer,fontFamily:T.body,fontSize:12,fontWeight:600 }}>—</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",
          padding:"11px 20px",borderTop:`1px solid ${T.border}`,background:T.faint }}>
          <span style={{ fontFamily:T.body,fontSize:12,fontWeight:600,color:T.textSec }}>
            {(logPage-1)*LOG_PAGE+1}–{Math.min(logPage*LOG_PAGE,filteredLog.length)} de {filteredLog.length}
          </span>
          <div style={{ display:"flex",gap:6 }}>
            <Btn onClick={()=>setLogPage(p=>Math.max(1,p-1))} disabled={logPage===1} variant="ghost" size="xs">‹ Anterior</Btn>
            <Btn onClick={()=>setLogPage(p=>Math.min(totalPages,p+1))} disabled={logPage===totalPages} variant="ghost" size="xs">Próximo ›</Btn>
          </div>
        </div>
      </Card>
    </div>
  );
};

/* ═══════════════════════════════════════════════════════════
   SCORING TABS
═══════════════════════════════════════════════════════════ */
const SCORING_TABS = [
  { id:"dashboard",  label:"Dashboard",        Icon:BarChart2   },
  { id:"rules",      label:"Regras de Score",   Icon:Star        },
  { id:"segments",   label:"Segmentação",       Icon:Filter      },
  { id:"automation", label:"Automação & Log",   Icon:Activity    },
];

/* ═══════════════════════════════════════════════════════════
   ROOT
═══════════════════════════════════════════════════════════ */
export default function VantariScoringSystem() {
  const [leads]  = useState(makeLeads);
  const [history]= useState(makeHistory);
  const [rules,setRules] = useState(DEFAULT_RULES);
  const [thresholds,setThresholds] = useState({warm:21,hot:51,sql:80});
  const [activeNav, setActiveNav] = useState("scoring");
  const [activeTab, setActiveTab] = useState("dashboard");

  return (
    <div style={{ display:"flex",minHeight:"100vh",background:T.bg,fontFamily:T.body }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700&family=Nunito+Sans:wght@400;500;600;700&display=swap');
        *,*::before,*::after{box-sizing:border-box;}
        input[type=range]{-webkit-appearance:none;height:5px;border-radius:99px;cursor:pointer;outline:none;}
        input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:16px;height:16px;border-radius:50%;background:var(--thumb,${T.blue});border:2px solid #fff;cursor:pointer;box-shadow:0 1px 4px rgba(0,0,0,0.2);}
        ::-webkit-scrollbar{width:5px;height:5px;}
        ::-webkit-scrollbar-track{background:transparent;}
        ::-webkit-scrollbar-thumb{background:#d1d9e0;border-radius:99px;}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
      `}</style>

      <Sidebar activeNav={activeNav} setActiveNav={setActiveNav}/>

      <div style={{ flex:1,display:"flex",flexDirection:"column",minWidth:0 }}>
        {/* Topbar */}
        <header style={{ background:T.surface,borderBottom:`1px solid ${T.border}`,
          padding:"0 28px",display:"flex",alignItems:"center",
          justifyContent:"space-between",height:53,position:"sticky",top:0,zIndex:50,flexShrink:0 }}>
          <div style={{ display:"flex",alignItems:"center",gap:8 }}>
            <h1 style={{ fontSize:16,fontWeight:700,color:T.text,fontFamily:T.heading,
              letterSpacing:"-0.01em",margin:0 }}>Scoring</h1>
            <span style={{ fontSize:13,color:T.textTer,fontFamily:T.body }}>—</span>
            <span style={{ fontSize:13,fontWeight:600,color:T.textSec,fontFamily:T.body }}>
              Sistema de pontuação de leads
            </span>
          </div>
          <div style={{ display:"flex",gap:8,alignItems:"center" }}>
            {[
              {k:"warm",c:T.orange},{k:"hot",c:T.green},{k:"sql",c:T.purple}
            ].map(({k,c})=>(
              <div key={k} style={{ fontFamily:T.body,fontSize:12,fontWeight:700,color:c,
                background:`${c}14`,border:`1px solid ${c}30`,
                padding:"4px 10px",borderRadius:7 }}>
                {k.toUpperCase()} ≥{thresholds[k]}
              </div>
            ))}
            <div style={{ width:33,height:33,borderRadius:"50%",background:T.blueLight,
              display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer" }}>
              <Bell size={16} color={T.blue}/>
            </div>
          </div>
        </header>

        {/* Secondary nav */}
        <div style={{ background:T.surface,borderBottom:`1px solid ${T.border}`,
          padding:"0 28px",display:"flex",gap:0,flexShrink:0 }}>
          {SCORING_TABS.map(tab=>(
            <button key={tab.id} onClick={()=>setActiveTab(tab.id)}
              style={{ display:"flex",alignItems:"center",gap:7,padding:"11px 17px",
                background:"none",border:"none",
                borderBottom:`2px solid ${activeTab===tab.id?T.blue:"transparent"}`,
                cursor:"pointer",fontSize:13,fontWeight:activeTab===tab.id?700:500,
                color:activeTab===tab.id?T.blue:T.textSec,fontFamily:T.body,
                transition:"all .15s" }}>
              <tab.Icon size={14}/>
              {tab.label}
            </button>
          ))}
        </div>

        {/* Content */}
        <main style={{ flex:1,padding:"24px 28px",overflowY:"auto",maxWidth:1360 }}>
          {activeTab==="dashboard"  && <ScoringDashboard leads={leads} thresholds={thresholds} history={history}/>}
          {activeTab==="rules"      && <ScoringRules rules={rules} setRules={setRules} thresholds={thresholds} setThresholds={setThresholds} leads={leads}/>}
          {activeTab==="segments"   && <SegmentBuilder leads={leads} thresholds={thresholds}/>}
          {activeTab==="automation" && <AutomationLog leads={leads} history={history} thresholds={thresholds}/>}
        </main>
      </div>
    </div>
  );
}
